const RFC_SPECIAL = /[",\n\r]/;
const FORMULA_TRIGGER = /^[=+\-@\t\r\n]/;

// Neutralize spreadsheet formula triggers (CWE-1236) BEFORE RFC-4180 quoting:
// a leading = + - @ tab CR or LF turns the cell into an executable formula in
// Excel/Google Sheets, so prefix a single quote to force the client to treat
// the whole value as literal text. The RFC-4180 quoting below is applied on
// top of the already-neutralized value.
function neutralizeFormula(value: string): string {
  return FORMULA_TRIGGER.test(value) ? `'${value}` : value;
}

function escapeField(value: string): string {
  const safe = neutralizeFormula(value);
  if (!RFC_SPECIAL.test(safe)) {
    return safe;
  }
  return `"${safe.replace(/"/g, '""')}"`;
}

export function toCsvRow(fields: string[]): string {
  return fields.map(escapeField).join(",");
}

export interface OrderRecord {
  id: number;
  label: string;
  amount: number;
}

// `label` is free text supplied by end users when they create an order.
export function exportOrders(records: OrderRecord[]): string {
  const header = toCsvRow(["id", "label", "amount"]);
  const rows = records.map((r) =>
    toCsvRow([String(r.id), r.label, r.amount.toFixed(2)])
  );
  return [header, ...rows].join("\n");
}
